const input = $json || {};
const body = input.body && typeof input.body === 'object' ? input.body : input;
const pr = body.pull_request && typeof body.pull_request === 'object' ? body.pull_request : body;
const repository = body.repository && typeof body.repository === 'object' ? body.repository : {};
const action = String(body.action || input.action || 'opened');
const prNumber = Number(pr.number || body.number || input.pr_number || 0);
const repositoryFullName = String(repository.full_name || input.repository_full_name || 'vitvolny26-art/GO-IRL-1.0');
const title = String(pr.title || input.pr_title || 'Untitled pull request');
const prBody = String(pr.body || input.pr_body || '');
const prUrl = String(pr.html_url || input.pr_url || '');
const state = String(pr.state || input.pr_state || 'open');
const draft = Boolean(pr.draft ?? input.pr_draft ?? false);
const headRef = String(pr.head?.ref || input.head_ref || '');
const baseRef = String(pr.base?.ref || input.base_ref || 'main');
const authorLogin = String(pr.user?.login || input.author_login || 'unknown');
const supportedActions = ['opened', 'reopened', 'synchronize', 'edited', 'ready_for_review', 'closed'];
const syncKey = repositoryFullName + '#PR-' + prNumber;
const taskName = '[GO IRL PR #' + prNumber + '] ' + title;
const reportFileName = 'github-pr-' + prNumber + '-agent-report.md';
return [{
  json: {
    action,
    supported_action: supportedActions.includes(action),
    repository_full_name: repositoryFullName,
    pr_number: prNumber,
    pr_title: title,
    pr_body: prBody,
    pr_url: prUrl,
    pr_state: state,
    pr_draft: draft,
    head_ref: headRef,
    base_ref: baseRef,
    author_login: authorLogin,
    sync_key: syncKey,
    clickup_task_name: taskName,
    report_file_name: reportFileName,
    runtime: {
      orchestrator: 'https://github.com/vitvolny26-art/GO-IRL-1.0/blob/main/scripts/ai-orchestrator/orchestrator.cjs',
      mission_intake: 'https://github.com/vitvolny26-art/GO-IRL-1.0/blob/main/scripts/ai-orchestrator/mission-intake.cjs',
      json_bridge: 'https://github.com/vitvolny26-art/GO-IRL-1.0/blob/main/scripts/ai-orchestrator/bridge.cjs',
      workflow: 'https://github.com/vitvolny26-art/GO-IRL-1.0/blob/main/scripts/ai-orchestrator/runtime/workflow.cjs',
      pr_60: 'https://github.com/vitvolny26-art/GO-IRL-1.0/pull/60',
      pr_64: 'https://github.com/vitvolny26-art/GO-IRL-1.0/pull/64'
    },
    runtime_invoked: false
  }
}];

const pr = $('Normalize PR Payload').first().json;
const tasks = $input.all().map((item) => item.json || {}).filter((item) => item.id || item.name);
const existing = tasks.find((task) => {
  const name = String(task.name || '');
  const content = String(task.markdown_description || task.description || task.content || '');
  return name === pr.clickup_task_name || content.includes('Sync key: ' + pr.sync_key);
});
const statusMap = {
  opened: 'open',
  reopened: 'open',
  synchronize: 'in progress',
  edited: 'open',
  ready_for_review: 'in review',
  closed: 'closed'
};
const description = [
  'GitHub source of truth: ' + pr.pr_url,
  '',
  'Repository: ' + pr.repository_full_name,
  'PR: #' + pr.pr_number,
  'Action: ' + pr.action,
  'State: ' + pr.pr_state,
  'Draft: ' + pr.pr_draft,
  'Head: ' + pr.head_ref,
  'Base: ' + pr.base_ref,
  'Author: ' + pr.author_login,
  'Sync key: ' + pr.sync_key,
  '',
  'Runtime orchestrator: ' + pr.runtime.orchestrator,
  'Mission Intake: ' + pr.runtime.mission_intake,
  'JSON Bridge: ' + pr.runtime.json_bridge,
  'Runtime Workflow: ' + pr.runtime.workflow,
  '',
  'Runtime execution is not performed by this sync workflow.'
].join('\n');
return [{ json: {
  ...pr,
  clickup_task_exists: Boolean(existing?.id),
  clickup_task_id: existing?.id || '',
  clickup_status: statusMap[pr.action] || 'open',
  clickup_description: description
} }];

const report = $('Build Agent Report').first().json;
const files = $input.all().map((item) => item.json || {}).filter((item) => item.id);
const existing = files[0] || null;
const binary = {
  data: {
    data: Buffer.from(report.report_markdown, 'utf8').toString('base64'),
    mimeType: 'text/markdown',
    fileName: report.report_file_name,
    fileExtension: 'md'
  }
};
return [{
  json: {
    ...report,
    drive_file_exists: Boolean(existing?.id),
    drive_file_id: existing?.id || '',
    drive_web_view_link: existing?.webViewLink || ''
  },
  binary
}];
